// CheckRow component for the checkbox
function CheckRow({ label, checked, onPress }) {
  return (
    <Pressable onPress={onPress} style={styles.checkRow}>
      <View style={[styles.checkBox, checked && styles.checkBoxOn]}>
        {checked && <Text style={styles.checkMark}>✓</Text>}
      </View>
      <Text style={styles.checkLabel}>{label}</Text>
    </Pressable>
  );
}

export default function VehicleOwnerFormScreen({ navigation }) {
  const { verification, setVerification, setFormProgress } = useContext(AppContext);
  const { updateCurrentStep } = useFormNavigation();
  const { t } = useTranslation();

  const [firstName, setFirstName] = useState(verification?.owner?.firstName || "");
  const [lastName, setLastName] = useState(verification?.owner?.lastName || "");
  const [idCardFile, setIdCardFile] = useState(verification?.pendingUploads?.ownerId || null);
  const [showConsentModal, setShowConsentModal] = useState(false);
  const [skipDocument, setSkipDocument] = useState(
    verification?.owner?.skipIdCard === true
  );

  useEffect(() => {
    updateCurrentStep("vehicle_owner_form_screen");
  }, []);

  // Auto-save in context
  useEffect(() => {
    const timeoutId = setTimeout(() => {
      const owner = {
        type: "PHYSIQUE",
        firstName: firstName,
        lastName: lastName,
        skipIdCard: skipDocument,
      };

      setVerification((prev) => ({
        ...prev,
        owner,
        pendingUploads: {
          ...(prev.pendingUploads || {}),
          ownerId: skipDocument ? null : idCardFile || null,
        },
      }));
    }, 600);
    return () => clearTimeout(timeoutId);
  }, [firstName, lastName, idCardFile, skipDocument, setVerification]);

  const allFieldsFilled = useMemo(() => {
    return firstName.trim().length > 0 && lastName.trim().length > 0 && (skipDocument || !!idCardFile);
  }, [firstName, lastName, idCardFile, skipDocument]);

  const pickIdCard = async () => {
    if (skipDocument) return;

    if (Platform.OS === "web") {
      const input = document.createElement("input");
      input.type = "file";
      input.accept = ".pdf,image/*";
      input.onchange = (event) => {
        const file = event.target.files && event.target.files[0];
        if (!file) return;
        setIdCardFile({
          uri: null,
          name: file.name,
          mimeType: file.type || "application/octet-stream",
          type: file.type || "application/octet-stream",
          __webFile: file,
        });
      };
      input.click();
      return;
    }

    const result = await DocumentPicker.getDocumentAsync({
      type: ["application/pdf", "image/*"],
      multiple: false,
    });

    if (result.type === "cancel") return;

    const asset = result.assets?.[0];
    if (!asset) return;

    setIdCardFile({
      uri: asset.uri,
      name: asset.name || "piece_identite",
      mimeType: asset.mimeType || "application/octet-stream",
      type: asset.mimeType || "application/octet-stream",
    });
  };

  const handleContinue = () => {
    if (!allFieldsFilled) return;

    // Save final owner data
    setVerification((prev) => ({
      ...prev,
      owner: {
        type: "PHYSIQUE",
        firstName: firstName.trim(),
        lastName: lastName.trim(),
        skipIdCard: skipDocument,
      },
      pendingUploads: {
        ...(prev.pendingUploads || {}),
        ownerId: skipDocument ? null : idCardFile,
      },
    }));

    setFormProgress((prev) => ({
      ...prev,
      completedSteps: [...new Set([...prev.completedSteps, "vehicle_owner_form_screen"])],
    }));

    setShowConsentModal(true);
  };

  return (
    <View style={styles.screen}>
      <Header />

      <ScrollView contentContainerStyle={styles.scrollContent} keyboardShouldPersistTaps="handled">
        <Pressable style={styles.backButton} onPress={() => navigation.navigate("ownership_screen")}>
          <Text style={styles.backButtonIcon}>←</Text>
        </Pressable>

        <Text style={styles.title}>{t("ownerForm.title")}</Text>
        <Text style={styles.subtitle}>
          {t("ownerForm.subtitle")}
        </Text>

        <View style={styles.card}>
          <Text style={styles.label}>{t("ownerForm.firstName")}</Text>
          <TextInput
            value={firstName}
            onChangeText={setFirstName}
            placeholder={t("ownerForm.firstNamePlaceholder")}
            placeholderTextColor="#9aa3af"
            style={styles.input}
          />

          <Text style={[styles.label, { marginTop: 12 }]}>{t("ownerForm.lastName")}</Text>
          <TextInput
            value={lastName}
            onChangeText={setLastName}
            placeholder={t("ownerForm.lastNamePlaceholder")}
            placeholderTextColor="#9aa3af"
            style={styles.input}
          />

          <View style={{ height: 16 }} />

          {/* Checkbox for skipping ID card */}
          <CheckRow
            label={t("documentUpload.skip")}
            checked={skipDocument}
            onPress={() => {
              setSkipDocument((v) => !v);
              if (!skipDocument) setIdCardFile(null);
            }}
          />

          {/* Upload section - only show if not skipping */}
          {!skipDocument && (
            <>
              <Pressable style={styles.uploadCard} onPress={pickIdCard}>
                <View style={styles.uploadInner}>
                  <Image source={require("../../../assets/file_upload.png")} style={styles.uploadIcon} />
                  <View style={{ flex: 1 }}>
                    <Text style={styles.uploadTitle}>{t("ownerForm.addIdCard")}</Text>
                    <Text style={styles.uploadHint}>{t("ownerForm.fileFormats")}</Text>
                  </View>
                </View>
              </Pressable>

              {!!idCardFile?.name && (
                <View style={styles.fileRow}>
                  <Text style={styles.fileName}>{idCardFile.name}</Text>
                  <Pressable onPress={() => setIdCardFile(null)}>
                    <Text style={styles.removeText}>{t("ownerForm.remove")}</Text>
                  </Pressable>
                </View>
              )}
            </>
          )}
        </View>

        <Pressable
          style={[styles.nextButton, !allFieldsFilled && styles.nextButtonDisabled]}
          disabled={!allFieldsFilled}
          onPress={handleContinue}
        >
          <Text style={styles.nextButtonText}>{t("common.continue")}</Text>
        </Pressable>
      </ScrollView>

      {showConsentModal && (
        <ConsentModal onDismiss={() => setShowConsentModal(false)} navigation={navigation} />
      )}
    </View>
  );
}

